from elasticsearch import Elasticsearch

# Initialize Elasticsearch client
es = Elasticsearch()

def execute_dynamic_script(req):
    script_code = req.get('script')
    if not script_code:
        raise ValueError("Script code is required")

    # Execute dynamic script using Elasticsearch Script API
    response = es.search(
        index="your_index_name",
        body={
            "size": 0,
            "aggs": {
                "dynamic_agg": {
                    "scripted_metric": {
                        "init_script": f"state = []",
                        "map_script": script_code,
                        "combine_script": "return state",
                        "reduce_script": "all_states.addAll(state); return all_states"
                    }
                }
            }
        }
    )
    return response

# Example usage
